// Simulate tool execution based on action
const action = $input.item.json.action;
const actionInput = $input.item.json.actionInput;

const mockResponses = {
  sql_query: {
    rows: [
      {order_id: 1001, customer: 'Acme GmbH', total: 1200.50, status: 'pending'},
      {order_id: 1002, customer: 'Beta AG',   total: 870.00,  status: 'pending'}
    ]
  },
  transform_data: {
    payload: [
      {order_id: 1001, customer_name: 'Acme GmbH', total_eur: 1200.50},
      {order_id: 1002, customer_name: 'Beta AG',   total_eur: 870.00}
    ]
  },
  erp_push: {status: 'ok', recordsImported: 2}
};

const observation = JSON.stringify(mockResponses[action] || {error: 'Unknown tool: ' + action});

return [{
  json: {
    ...$input.item.json,
    observation
  }
}];

// Record benchmark metrics
const state = $input.item.json;
const finalAnswer = state.finalAnswer;

console.log('=== BENCHMARK RESULT ===');
console.log('Final Answer:', finalAnswer);
console.log('Step Count:', state.stepCount);
console.log('=== Fill in evaluation/results/SC-01_artefact_run001.json ===');

return [{
  json: {
    finalAnswer,
    stepCount: state.stepCount,
    success: finalAnswer && finalAnswer.length > 0,
    reminder: 'Fill in evaluation/results/SC-01_artefact_run001.json'
  }
}];
